     1→/**
     2→ * ConvergioEdu PDF Processor
     3→ * Client-side PDF to image conversion using pdf.js
     4→ *
     5→ * Converts PDF pages to images for Vision API analysis.
     6→ * Uses Mozilla's pdf.js library for rendering.
     7→ *
     8→ * Related: Issue #21, ADR-0001
     9→ */
    10→
    11→import * as pdfjsLib from 'pdfjs-dist';
    12→import { logger } from '@/lib/logger';
    13→
    14→// Configure pdf.js worker
    15→// The worker is loaded from CDN for optimal bundle size
