    18→}
    19→
    20→/**
    21→ * Maximum number of pages to process
    22→ * Prevents overwhelming the Vision API with too many requests
    23→ */
    24→export const MAX_PDF_PAGES = 5;
    25→
    26→/**
    27→ * Default rendering scale for high-quality output
    28→ * 2.0 gives good quality without excessive file size
    29→ */
    30→export const DEFAULT_SCALE = 2.0;
    31→
    32→/**
    33→ * Result of processing a single PDF page
    34→ */
    35→export interface ProcessedPage {
    36→  pageNumber: number;
    37→  imageData: string; // Base64 data URL
    38→  width: number;
    39→  height: number;
    40→}
    41→
    42→/**
    43→ * Result of processing an entire PDF
    44→ */
    45→export interface ProcessedPDF {
    46→  totalPages: number;
    47→  processedPages: number;
    48→  pages: ProcessedPage[];
    49→  truncated: boolean; // True if totalPages > MAX_PDF_PAGES
    50→  filename: string;
    51→}
    52→
    53→/**
    54→ * PDF processing error
    55→ */
    56→export class PDFProcessingError extends Error {
    57→  constructor(
    58→    message: string,
    59→    public readonly code: 'LOAD_FAILED' | 'RENDER_FAILED' | 'ENCRYPTED' | 'INVALID' | 'TOO_LARGE',
    60→    public readonly cause?: Error
    61→  ) {
    62→    super(message);
    63→    this.name = 'PDFProcessingError';
    64→  }
    65→}
    66→
    67→/**
    68→ * Options for PDF processing
    69→ */
    70→export interface PDFProcessOptions {
    71→  /** Rendering scale (default: 2.0) */
    72→  scale?: number;
    73→  /** Maximum pages to process (default: MAX_PDF_PAGES) */
    74→  maxPages?: number;
    75→  /** Specific page numbers to process (1-indexed) */
    76→  pageNumbers?: number[];
    77→  /** Image format (default: 'image/jpeg') */
    78→  format?: 'image/jpeg' | 'image/png';
    79→  /** JPEG quality (default: 0.9) */
    80→  quality?: number;
    81→}
    82→
    83→/**
    84→ * Check if a file is a PDF
    85→ */
    86→export function isPDF(file: File): boolean {
    87→  return (
    88→    file.type === 'application/pdf' ||
    89→    file.name.toLowerCase().endsWith('.pdf')
    90→  );
    91→}
    92→
    93→/**
    94→ * Get PDF metadata without full processing
    95→ */
    96→export async function getPDFInfo(
    97→  file: File
    98→): Promise<{ numPages: number; filename: string }> {
    99→  try {
   100→    const arrayBuffer = await file.arrayBuffer();
   101→    const pdf = await pdfjsLib.getDocument({ data: arrayBuffer }).promise;
   102→
   103→    return {
   104→      numPages: pdf.numPages,
   105→      filename: file.name,
   106→    };
   107→  } catch (error) {
   108→    if (error instanceof Error && error.message.includes('password')) {
   109→      throw new PDFProcessingError(
   110→        'Il PDF è protetto da password. Rimuovi la protezione e riprova.',
   111→        'ENCRYPTED',
   112→        error
   113→      );
   114→    }
   115→    throw new PDFProcessingError(
   116→      'Impossibile leggere il PDF. Il file potrebbe essere danneggiato.',
   117→      'LOAD_FAILED',
   118→      error instanceof Error ? error : undefined
   119→    );
   120→  }
   121→}
   122→
   123→/**
   124→ * Process a PDF file and convert pages to images
   125→ *
   126→ * @param file - The PDF file to process
   127→ * @param options - Processing options
   128→ * @returns Processed PDF with page images
   129→ */
   130→export async function processPDF(
   131→  file: File,
   132→  options: PDFProcessOptions = {}
   133→): Promise<ProcessedPDF> {
   134→  const {
   135→    scale = DEFAULT_SCALE,
   136→    maxPages = MAX_PDF_PAGES,
   137→    pageNumbers,
   138→    format = 'image/jpeg',
   139→    quality = 0.9,
   140→  } = options;
   141→
   142→  try {
   143→    const arrayBuffer = await file.arrayBuffer();
   144→    const pdf = await pdfjsLib.getDocument({ data: arrayBuffer }).promise;
   145→
   146→    const totalPages = pdf.numPages;
   147→    const pagesToProcess = pageNumbers
   148→      ? pageNumbers.filter((n) => n >= 1 && n <= totalPages)
   149→      : Array.from({ length: Math.min(totalPages, maxPages) }, (_, i) => i + 1);
   150→
   151→    const pages: ProcessedPage[] = [];
   152→
   153→    for (const pageNum of pagesToProcess) {
   154→      try {
   155→        const page = await pdf.getPage(pageNum);
   156→        const viewport = page.getViewport({ scale });
   157→
   158→        // Create canvas for rendering
   159→        const canvas = document.createElement('canvas');
   160→        canvas.width = viewport.width;
   161→        canvas.height = viewport.height;
   162→
   163→        const context = canvas.getContext('2d');
   164→        if (!context) {
   165→          throw new Error('Failed to get canvas context');
   166→        }
   167→
   168→        // Render page to canvas (canvas property required for pdfjs-dist v5)
   169→        await page.render({
   170→          canvasContext: context,
   171→          viewport,
   172→          canvas,
   173→        } as Parameters<typeof page.render>[0]).promise;
   174→
   175→        // Convert to image
   176→        const imageData = canvas.toDataURL(format, quality);
   177→
   178→        pages.push({
   179→          pageNumber: pageNum,
   180→          imageData,
   181→          width: viewport.width,
   182→          height: viewport.height,
   183→        });
   184→      } catch (renderError) {
   185→        logger.error(`Failed to render page ${pageNum}`, { error: renderError });
   186→        // Continue with other pages
   187→      }
   188→    }
   189→
   190→    if (pages.length === 0) {
   191→      throw new PDFProcessingError(
   192→        'Impossibile elaborare nessuna pagina del PDF.',
   193→        'RENDER_FAILED'
   194→      );
   195→    }
   196→
   197→    return {
   198→      totalPages,
   199→      processedPages: pages.length,
   200→      pages,
   201→      truncated: totalPages > maxPages && !pageNumbers,
   202→      filename: file.name,
   203→    };
   204→  } catch (error) {
   205→    if (error instanceof PDFProcessingError) {
   206→      throw error;
   207→    }
   208→
   209→    if (error instanceof Error) {
   210→      if (error.message.includes('password')) {
   211→        throw new PDFProcessingError(
   212→          'Il PDF è protetto da password. Rimuovi la protezione e riprova.',
   213→          'ENCRYPTED',
   214→          error
   215→        );
   216→      }
   217→      if (error.message.includes('Invalid PDF')) {
   218→        throw new PDFProcessingError(
   219→          'Il file non è un PDF valido.',
   220→          'INVALID',
   221→          error
   222→        );
   223→      }
   224→    }
   225→
   226→    throw new PDFProcessingError(
   227→      'Errore durante l\'elaborazione del PDF. Riprova.',
   228→      'LOAD_FAILED',
   229→      error instanceof Error ? error : undefined
   230→    );
   231→  }
   232→}
   233→
   234→/**
   235→ * Generate a thumbnail for the first page of a PDF
   236→ *
   237→ * @param file - The PDF file
   238→ * @param thumbnailWidth - Desired thumbnail width (default: 200)
   239→ * @returns Base64 data URL of the thumbnail
   240→ */
   241→export async function generatePDFThumbnail(
   242→  file: File,
   243→  thumbnailWidth = 200
   244→): Promise<string> {
   245→  const result = await processPDF(file, {
   246→    maxPages: 1,
   247→    scale: 1.0,
   248→    quality: 0.8,
   249→  });
   250→
   251→  if (result.pages.length === 0) {
   252→    throw new PDFProcessingError(
   253→      'Impossibile generare la miniatura del PDF.',
   254→      'RENDER_FAILED'
   255→    );
   256→  }
   257→
   258→  const page = result.pages[0];
   259→
   260→  // Resize if needed
   261→  if (page.width > thumbnailWidth) {
   262→    const canvas = document.createElement('canvas');
   263→    const scale = thumbnailWidth / page.width;
   264→    canvas.width = thumbnailWidth;
   265→    canvas.height = page.height * scale;
   266→
   267→    const ctx = canvas.getContext('2d');
   268→    if (!ctx) {
   269→      return page.imageData;
   270→    }
   271→
   272→    const img = new Image();
   273→    await new Promise<void>((resolve, reject) => {
   274→      img.onload = () => resolve();
   275→      img.onerror = reject;
   276→      img.src = page.imageData;
   277→    });
   278→
   279→    ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
   280→    return canvas.toDataURL('image/jpeg', 0.8);
   281→  }
   282→
   283→  return page.imageData;
   284→}
