    93→- Usa create_summary per costruire il riassunto
    94→- Includi punti chiave per ogni sezione
    95→- Adatta la lunghezza alle esigenze dello studente (breve/medio/lungo)
    96→- Fai domande per approfondire i punti importanti`,
    97→};
    98→
    99→export async function POST(request: NextRequest) {
   100→  // Rate limiting: 20 requests per minute per IP
   101→  const clientId = getClientIdentifier(request);
   102→  const rateLimit = checkRateLimit(`chat:${clientId}`, RATE_LIMITS.CHAT);
   103→
   104→  if (!rateLimit.success) {
   105→    logger.warn('Rate limit exceeded', { clientId, endpoint: '/api/chat' });
   106→    return rateLimitResponse(rateLimit);
   107→  }
   108→
   109→  try {
   110→    const body: ChatRequest = await request.json();
   111→    const { messages, systemPrompt, maestroId, enableTools = true, enableMemory = true, requestedTool } = body;
   112→
   113→    if (!messages || !Array.isArray(messages)) {
   114→      return NextResponse.json(
   115→        { error: 'Messages array is required' },
   116→        { status: 400 }
   117→      );
   118→    }
   119→
   120→    // Get userId from cookie for memory injection and provider preference
   121→    const cookieStore = await cookies();
   122→    const userId = cookieStore.get('convergio-user-id')?.value;
   123→
   124→    // #87: Get user's provider preference from settings
   125→    let providerPreference: AIProvider | 'auto' | undefined;
   126→    if (userId) {
   127→      try {
   128→        const settings = await prisma.settings.findUnique({
   129→          where: { userId },
   130→          select: { provider: true },
   131→        });
   132→        if (settings?.provider && (settings.provider === 'azure' || settings.provider === 'ollama')) {
   133→          providerPreference = settings.provider;
   134→        }
   135→      } catch (e) {
   136→        // Settings lookup failure should not block chat
   137→        logger.debug('Failed to load provider preference', { error: String(e) });
   138→      }
   139→    }
   140→
   141→    // Build enhanced system prompt with tool context
   142→    let enhancedSystemPrompt = systemPrompt;
   143→    if (requestedTool && TOOL_CONTEXT[requestedTool]) {
   144→      enhancedSystemPrompt = `${systemPrompt}\n\n${TOOL_CONTEXT[requestedTool]}`;
   145→      logger.debug('Tool context injected', { requestedTool, maestroId });
   146→    }
   147→
   148→    // Inject conversation memory if enabled and user is authenticated (ADR 0021)
   149→    let hasMemory = false;
   150→    if (enableMemory && userId && maestroId) {
   151→      try {
   152→        const memory = await loadPreviousContext(userId, maestroId);
   153→        if (memory.recentSummary || memory.keyFacts.length > 0) {
   154→          enhancedSystemPrompt = enhanceSystemPrompt({
   155→            basePrompt: enhancedSystemPrompt,
   156→            memory,
   157→            safetyOptions: {
   158→              role: 'maestro',
   159→            },
   160→          });
   161→          hasMemory = true;
   162→          logger.debug('Conversation memory injected', {
   163→            maestroId,
   164→            keyFactCount: memory.keyFacts.length,
   165→            hasSummary: !!memory.recentSummary,
   166→          });
   167→        }
   168→      } catch (memoryError) {
   169→        // Memory loading failure should not block the chat
   170→        logger.warn('Failed to load conversation memory', {
   171→          userId,
   172→          maestroId,
   173→          error: String(memoryError),
   174→        });
   175→      }
   176→    }
   177→
   178→    // SECURITY: Filter the last user message for safety (Issue #30)
   179→    const lastUserMessage = messages.filter(m => m.role === 'user').pop();
   180→    if (lastUserMessage) {
   181→      const filterResult = filterInput(lastUserMessage.content);
   182→      if (!filterResult.safe && filterResult.action === 'block') {
   183→        logger.warn('Content blocked by safety filter', {
   184→          clientId,
   185→          category: filterResult.category,
   186→          severity: filterResult.severity,
   187→        });
   188→        return NextResponse.json({
   189→          content: filterResult.suggestedResponse,
   190→          provider: 'safety_filter',
   191→          model: 'content-filter',
   192→          blocked: true,
   193→          category: filterResult.category,
   194→        });
   195→      }
   196→    }
   197→
   198→    // #87: Get active provider info for response (pass preference for consistency)
   199→    const providerConfig = getActiveProvider(providerPreference);
   200→
   201→    try {
   202→      // Call AI with optional tool definitions
   203→      // Cast to mutable array since chatCompletion expects ToolDefinition[]
   204→      // #87: Pass user's provider preference to chatCompletion
   205→      const result = await chatCompletion(messages, enhancedSystemPrompt, {
   206→        tools: enableTools ? ([...CHAT_TOOL_DEFINITIONS] as typeof CHAT_TOOL_DEFINITIONS[number][]) : undefined,
   207→        tool_choice: enableTools ? 'auto' : 'none',
   208→        providerPreference,
   209→      });
   210→
   211→      // Handle tool calls if present
   212→      if (result.tool_calls && result.tool_calls.length > 0) {
   213→        const toolResults = [];
   214→
   215→        for (const toolCall of result.tool_calls) {
   216→          try {
   217→            const args = JSON.parse(toolCall.function.arguments);
   218→            const toolResult = await executeToolCall(
   219→              toolCall.function.name,
   220→              args,
   221→              { maestroId, conversationId: undefined, userId }
   222→            );
   223→            // Transform to ToolCall interface format expected by ToolResultDisplay
   224→            // Note: type uses function name (e.g., 'create_mindmap') to match ToolType in types/index.ts
   225→            toolResults.push({
   226→              id: toolResult.toolId || toolCall.id,
   227→              type: toolCall.function.name,
   228→              name: toolCall.function.name,
   229→              arguments: args,
   230→              status: toolResult.success ? 'completed' : 'error',
   231→              result: {
   232→                success: toolResult.success,
   233→                data: toolResult.data,
   234→                error: toolResult.error,
   235→              },
   236→            });
   237→          } catch (toolError) {
   238→            logger.error('Tool execution failed', {
   239→              toolCall: toolCall.function.name,
   240→              error: String(toolError),
   241→            });
   242→            const args = JSON.parse(toolCall.function.arguments || '{}');
   243→            toolResults.push({
   244→              id: toolCall.id,
   245→              type: toolCall.function.name,
   246→              name: toolCall.function.name,
   247→              arguments: args,
   248→              status: 'error',
   249→              result: {
   250→                success: false,
   251→                error: toolError instanceof Error ? toolError.message : 'Tool execution failed',
   252→              },
   253→            });
   254→          }
