     1→/**
     2→ * API Route: Create Tool
     3→ *
     4→ * Creates a new tool from voice commands and broadcasts events.
     5→ * Part of I-02: Voice Tool Commands.
     6→ */
     7→
     8→import { NextRequest, NextResponse } from 'next/server';
     9→import { logger } from '@/lib/logger';
    10→import {
    11→  createToolState,
    12→  updateToolState,
    13→  completeToolState,
    14→} from '@/lib/realtime/tool-state';
    15→import {
    16→  broadcastToolEvent,
    17→  type ToolType,
    18→} from '@/lib/realtime/tool-events';
    19→import { validateAuth, validateSessionOwnership } from '@/lib/auth/session-auth';
    20→
    21→// Valid tool types
    22→const VALID_TOOL_TYPES: ToolType[] = [
    23→  'mindmap',
    24→  'flashcards',
    25→  'quiz',
    26→  'summary',
    27→  'timeline',
    28→  'diagram',
    29→];
    30→
    31→interface CreateToolRequest {
    32→  sessionId: string;
    33→  maestroId: string;
    34→  toolType: ToolType;
    35→  title: string;
    36→  subject?: string;
    37→  content: Record<string, unknown>;
    38→}
    39→
    40→/**
    41→ * Create a new tool from voice command
    42→ *
    43→ * Body:
    44→ * - sessionId: Current session ID
    45→ * - maestroId: Maestro creating the tool
    46→ * - toolType: Type of tool to create
    47→ * - title: Tool title
    48→ * - subject: Optional subject
    49→ * - content: Tool content/arguments
    50→ */
    51→export async function POST(request: NextRequest) {
    52→  try {
    53→    // #83: Authentication check - tool creation requires authenticated user
    54→    const auth = await validateAuth();
    55→    if (!auth.authenticated || !auth.userId) {
    56→      return NextResponse.json(
    57→        { error: 'Authentication required' },
    58→        { status: 401 }
    59→      );
    60→    }
    61→
    62→    const body: CreateToolRequest = await request.json();
    63→    const { sessionId, maestroId, toolType, title, subject, content } = body;
    64→
    65→    // Validate required fields
    66→    if (!sessionId || !maestroId || !toolType || !title) {
    67→      return NextResponse.json(
    68→        {
    69→          error: 'Missing required fields',
    70→          required: ['sessionId', 'maestroId', 'toolType', 'title'],
    71→        },
    72→        { status: 400 }
    73→      );
    74→    }
    75→
    76→    // Validate tool type
    77→    if (!VALID_TOOL_TYPES.includes(toolType)) {
    78→      return NextResponse.json(
    79→        {
    80→          error: 'Invalid tool type',
    81→          validTypes: VALID_TOOL_TYPES,
    82→        },
    83→        { status: 400 }
    84→      );
    85→    }
    86→
    87→    // Validate session ID format
    88→    if (!/^[a-zA-Z0-9_-]{1,64}$/.test(sessionId)) {
    89→      return NextResponse.json(
    90→        { error: 'Invalid sessionId format' },
    91→        { status: 400 }
    92→      );
    93→    }
    94→
    95→    // #83: Verify session ownership - user can only create tools in their own sessions
    96→    const ownsSession = await validateSessionOwnership(sessionId, auth.userId);
    97→    if (!ownsSession) {
    98→      return NextResponse.json(
    99→        { error: 'Session not found or access denied' },
   100→        { status: 403 }
   101→      );
   102→    }
   103→
   104→    // Generate tool ID
   105→    const toolId = `voice-tool-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
   106→
   107→    // Create tool state
   108→    const toolState = createToolState({
   109→      id: toolId,
   110→      type: toolType,
   111→      sessionId,
   112→      maestroId,
   113→      title,
   114→      subject,
   115→    });
   116→
   117→    // Broadcast tool:created event
   118→    broadcastToolEvent({
   119→      id: toolId,
   120→      type: 'tool:created',
   121→      toolType,
   122→      sessionId,
   123→      maestroId,
   124→      timestamp: Date.now(),
   125→      data: {
   126→        title,
   127→        subject,
   128→      },
   129→    });
   130→
   131→    logger.info('Tool created from voice command', {
   132→      toolId,
   133→      toolType,
   134→      sessionId,
   135→      maestroId,
   136→      title,
   137→    });
   138→
   139→    // If content is provided, update the tool state with it
   140→    if (content && Object.keys(content).length > 0) {
   141→      updateToolState(toolId, {
   142→        content,
   143→        progress: 50,
   144→      });
   145→
   146→      // Broadcast progress update
   147→      broadcastToolEvent({
   148→        id: toolId,
   149→        type: 'tool:update',
   150→        toolType,
   151→        sessionId,
   152→        maestroId,
   153→        timestamp: Date.now(),
   154→        data: {
   155→          progress: 50,
   156→        },
   157→      });
   158→    }
   159→
   160→    // Complete the tool (for voice commands, content is usually complete)
   161→    // Cast through unknown since voice content may not exactly match ToolContent types
   162→    completeToolState(toolId, content as unknown as Parameters<typeof completeToolState>[1]);
   163→
